// Bicep: Deploy at Management Group scope
// Deploy with: az deployment mg create --management-group-id Corp --location eastus --template-file mg.bicep

targetScope = 'managementGroup'

// Create a child management group under Corp
resource corpProd 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'Corp-Prod'
  scope: tenant()
  properties: {
    displayName: 'Corp Production'
    details: {
      parent: {
        id: '/providers/Microsoft.Management/managementGroups/Corp'
      }
    }
  }
}

// Assign a built-in policy at management group scope
resource allowedLocations 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'allowed-locations-corp'
  properties: {
    displayName: 'Allowed locations for Corp'
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/e56962a6-4747-49cd-b67b-bf8b01975c4f'
    parameters: {
      listOfAllowedLocations: {
        value: ['eastus', 'westus2', 'northeurope']
      }
    }
  }
}

// Assign a Reader role to a security group at Corp management group scope
resource securityReaderAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(managementGroup().id, 'Reader', 'security-group-object-id')
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', 'acdd72a7-3385-48ef-bd42-f606fba81ae7')
    principalId: 'security-group-object-id'
    principalType: 'Group'
  }
}

# Terraform: Management Groups and policy assignment
# Requires azurerm provider 3.x+

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
  }
}

# Create management group hierarchy
resource "azurerm_management_group" "corp" {
  display_name = "Corporate"
  name         = "Corp"
}

resource "azurerm_management_group" "corp_prod" {
  display_name               = "Corp Production"
  name                       = "Corp-Prod"
  parent_management_group_id = azurerm_management_group.corp.id
}

# Assign policy at management group scope
resource "azurerm_management_group_policy_assignment" "allowed_locations" {
  name                 = "allowed-locations-corp"
  management_group_id  = azurerm_management_group.corp.id
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/e56962a6-4747-49cd-b67b-bf8b01975c4f"
  display_name         = "Allowed locations for Corp"

  parameters = jsonencode({
    listOfAllowedLocations = {
      value = ["eastus", "westus2", "northeurope"]
    }
  })
}

# Assign role at management group scope
resource "azurerm_role_assignment" "security_reader" {
  scope              = azurerm_management_group.corp.id
  role_definition_name = "Reader"
  principal_id       = var.security_group_object_id
}
